import React, { useState } from 'react';
import { ChevronLeft, ChevronRight, Star } from 'lucide-react';

const testimonials = [
  {
    quote: "Canvas Creative transformed how we approach project showcases. The minimalist design and intuitive tools allowed us to present our work with unparalleled elegance and professionalism. Highly recommend!",
    author: "Alice Johnson",
    title: "Lead Designer, Pixel Studio",
    avatar: "https://images.unsplash.com/photo-1494790108377-be9c29b29329?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=facearea&facepad=2&w=256&h=256&q=80",
  },
  {
    quote: "The collaboration features are a game-changer! My team can now work seamlessly, share ideas, and iterate faster than ever before. Canvas Creative truly understands the needs of modern creative teams.",
    author: "Bob Williams",
    title: "Creative Director, Visionary Arts",
    avatar: "https://images.unsplash.com/photo-1500648767791-00dcc994a43e?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=facearea&facepad=2&w=256&h=256&q=80",
  },
  {
    quote: "Finally, a platform that puts design first without sacrificing functionality. My clients are consistently impressed with the presentations I create using Canvas Creative. It's an indispensable tool.",
    author: "Charlie Brown",
    title: "Freelance Artist",
    avatar: "https://images.unsplash.com/photo-1534528741775-53994a69daeb?ixlib=rb-4.0.3&ixid=MnwxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8&auto=format&fit=facearea&facepad=2&w=256&h=256&q=80",
  },
];

const TestimonialCarousel = () => {
  const [currentIndex, setCurrentIndex] = useState(0);

  const goToPrevious = () => {
    setCurrentIndex((prevIndex) => (prevIndex === 0 ? testimonials.length - 1 : prevIndex - 1));
  };

  const goToNext = () => {
    setCurrentIndex((prevIndex) => (prevIndex === testimonials.length - 1 ? 0 : prevIndex + 1));
  };

  return (
    <section id="testimonials" className="py-20 md:py-28 lg:py-36 bg-zinc-50 px-4 sm:px-6 lg:px-8">
      <div className="max-w-4xl mx-auto text-center">
        <h2 className="text-4xl sm:text-5xl font-bold text-zinc-900 mb-12 font-heading tracking-tight">
          What Our Clients Say
        </h2>

        <div className="relative bg-zinc-800 text-white p-8 md:p-12 rounded-xl shadow-xl border border-zinc-700">
          <div className="flex justify-center mb-4">
            {[...Array(5)].map((_, i) => (
              <Star key={i} className="text-yellow-400 fill-yellow-400 w-6 h-6 mx-0.5" />
            ))}
          </div>
          <p className="text-xl md:text-2xl italic leading-relaxed mb-8">
            "{testimonials[currentIndex].quote}"
          </p>
          <div className="flex items-center justify-center space-x-4">
            <img
              src={testimonials[currentIndex].avatar}
              alt={testimonials[currentIndex].author}
              className="w-16 h-16 rounded-full object-cover border-2 border-zinc-600"
            />
            <div>
              <p className="font-semibold text-lg">{testimonials[currentIndex].author}</p>
              <p className="text-zinc-300 text-md">{testimonials[currentIndex].title}</p>
            </div>
          </div>

          {/* Navigation Arrows */}
          <button
            onClick={goToPrevious}
            className="absolute left-4 top-1/2 -translate-y-1/2 p-3 bg-zinc-700 hover:bg-zinc-600 rounded-full shadow-md transition-colors duration-300 focus:outline-none focus:ring-2 focus:ring-zinc-500"
            aria-label="Previous testimonial"
          >
            <ChevronLeft size={24} className="text-white" />
          </button>
          <button
            onClick={goToNext}
            className="absolute right-4 top-1/2 -translate-y-1/2 p-3 bg-zinc-700 hover:bg-zinc-600 rounded-full shadow-md transition-colors duration-300 focus:outline-none focus:ring-2 focus:ring-zinc-500"
            aria-label="Next testimonial"
          >
            <ChevronRight size={24} className="text-white" />
          </button>

          {/* Dots Indicator */}
          <div className="absolute -bottom-10 left-1/2 -translate-x-1/2 flex space-x-2 mt-4">
            {testimonials.map((_, idx) => (
              <button
                key={idx}
                onClick={() => setCurrentIndex(idx)}
                className={`w-3 h-3 rounded-full transition-all duration-300 ${
                  idx === currentIndex ? 'bg-zinc-700 w-5' : 'bg-zinc-300'
                }`}
                aria-label={`Go to testimonial ${idx + 1}`}
              ></button>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default TestimonialCarousel;

